        public static Tween Custom<T>(
            [NotNull] T target,
            float startValue,
            float endValue,
            float duration,
            [NotNull] Action<T, float> onValueChange,
            Easing ease = default,
            int cycles = 1,
            CycleMode cycleMode = CycleMode.Restart,
            float startDelay = 0,
            float endDelay = 0,
            bool useUnscaledTime = false
        ) where T : class =>
            CustomInternal(
                target,
                new TweenSettings<float>(
                    startValue,
