                ),
                onValueChange
            );

        public static Tween Custom<T>(
            [NotNull] T target,
            TweenSettings<float> settings,
            [NotNull] Action<T, float> onValueChange
        ) where T : class =>
            CustomInternal(target, settings, onValueChange);

        public static Tween Custom(TweenSettings<float> settings, [NotNull] Action<float> onValueChange) {
            Assert.IsNotNull(onValueChange);

            if (settings.startFromCurrent) {
                UnityEngine.Debug.LogWarning(Constants.kCustomTweensDontSupportStartFromCurrentWarning);
            }

            if (PrimeTweenManager.Instance.IsDestroyed) {
                return default;
            }

            var tween = PrimeTweenManager.FetchTween(settings.settings._updateType);
            ref var rt = ref tween.ManagedData;
            ref var d = ref tween.Data;

            d.startValue.CopyFrom(ref settings.startValue);
            rt.endValueOrDiff.CopyFrom(ref settings.endValue);

            tween.customOnValueChange = onValueChange;

            tween.Setup(
                PrimeTweenManager.sDummyTarget,
                ref settings.settings,
                false,
                TweenType.CustomFloat,
                ref rt,
                ref d
            );

            tween.onValueChange = (ref TweenData rt2, ref UnmanagedTweenData d2) => {
                if (d2.IsUpdating) {
                    UnityEngine.Debug.LogError(Constants.kRecursiveCallError);
                    return;
                }

                d2.IsUpdating = true;

                var startValue = d2.startValue;
                var t = d2.easedInterpolationFactor;
                var diff = rt2.endValueOrDiff;
                var val = TweenData.FloatVal(startValue, t, diff);
                var customOnValueChange = rt2.cold.customOnValueChange as Action<float>;

                try {
                    customOnValueChange(val);
                } finally {
                    d2.IsUpdating = false;
                }
            };

            return PrimeTweenManager.Animate(ref rt, ref d);
        }

        private static Tween CustomInternal<T>(
            [NotNull] T target,
            TweenSettings<float> settings,
            [NotNull] Action<T, float> onValueChange,
            bool isAdditive = false
        ) where T : class {
            Assert.IsNotNull(onValueChange);

            if (settings.startFromCurrent) {
                UnityEngine.Debug.LogWarning(Constants.kCustomTweensDontSupportStartFromCurrentWarning);
            }

            if (PrimeTweenManager.Instance.IsDestroyed) {
                return default;
            }

            var tween = PrimeTweenManager.FetchTween(settings.settings._updateType);
            ref var rt = ref tween.ManagedData;
            ref var d = ref tween.Data;

            d.startValue.CopyFrom(ref settings.startValue);
            d.IsAdditive = isAdditive;
            rt.endValueOrDiff.CopyFrom(ref settings.endValue);

            tween.customOnValueChange = onValueChange;
            tween.Setup(target, ref settings.settings, false, TweenType.CustomFloat, ref rt, ref d);

            tween.onValueChange = (ref TweenData rt2, ref UnmanagedTweenData d2) => {
                if (d2.IsUpdating) {
                    UnityEngine.Debug.LogError(Constants.kRecursiveCallError);
                    return;
                }

                d2.IsUpdating = true;

                var startValue = d2.startValue;
                var t = d2.easedInterpolationFactor;
                var dataIsAdditive = d2.IsAdditive;

                var rt2Target = rt2.target as T;
                var diff = rt2.endValueOrDiff;

                float val;

                if (dataIsAdditive) {
                    var newVal = TweenData.FloatVal(startValue, t, diff);
                    val = newVal.CalcDelta(rt2.cold.prevVal);
                    rt2.cold.prevVal.single = newVal;
                } else {
                    val = TweenData.FloatVal(startValue, t, diff);
                }

                var customOnValueChange = rt2.cold.customOnValueChange as Action<T, float>;

                try {
                    customOnValueChange(rt2Target, val);
                } finally {
                    d2.IsUpdating = false;
                }
            };

            return PrimeTweenManager.Animate(ref rt, ref d);
        }

        private static Tween Animate(object target, ref TweenSettings<float> settings, TweenType tweenType) {
            if (PrimeTweenManager.Instance.IsDestroyed) {
                return default;
            }

            var tween = PrimeTweenManager.FetchTween(settings.settings._updateType);
            ref var d = ref tween.Data;
            ref var rt = ref tween.ManagedData;

            d.startValue.CopyFrom(ref settings.startValue);
            rt.endValueOrDiff.CopyFrom(ref settings.endValue);

            tween.Setup(target, ref settings.settings, settings.startFromCurrent, tweenType, ref rt, ref d);
            return PrimeTweenManager.Animate(ref rt, ref d);
        }

        static Tween AnimateMaterial(
            [CanBeNull] object target,
            long longParam,
            ref TweenSettings<float> settings,
            TweenType tweenType
        ) {
            if (PrimeTweenManager.Instance.IsDestroyed) {
                return default;
            }
#if DEVELOPMENT_BUILD || UNITY_EDITOR
            int propId = (int)longParam;

            if (target is UnityEngine.Material material && !Utils.IsValidMaterialProperty(tweenType, target, propId)) {
                UnityEngine.Debug.LogWarning($"Material doesn't have a property with id '{propId}'.", material);
            }

            if (target is UnityEngine.Renderer renderer && !Utils.IsValidMaterialProperty(tweenType, target, propId)) {
                UnityEngine.Debug.LogWarning(
                    $"Renderer's material doesn't have a property with id '{propId}'.",
                    renderer
                );
            }
#endif
            var tween = PrimeTweenManager.FetchTween(settings.settings._updateType);
            ref var d = ref tween.Data;
            ref var rt = ref tween.ManagedData;

            d.startValue.CopyFrom(ref settings.startValue);
            rt.endValueOrDiff.CopyFrom(ref settings.endValue);

            tween.longParam = longParam;
            tween.Setup(target, ref settings.settings, settings.startFromCurrent, tweenType, ref rt, ref d);
            return PrimeTweenManager.Animate(ref rt, ref d);
        }

